/**
 * @fileoverview GridEditor events — centralised event binding for toolbar,
 *               row headers, keyboard shortcuts, block property panels,
 *               color pickers, and the component picker menu.
 *
 * Every exported function receives a thin `ctx` context object that proxies
 * access to the class's private fields (see index.js `#ctx()`).
 *
 * @module module/GridEditor/events
 */

import { PRESETS, PART } from './constants.js';
import { el, getInsertRowIndex, findBlock, calcDropIndex } from './helpers.js';
import { createBlock, pushUndo } from './state.js';
import { bindPluginProps, attachColorPickers, closeColorPopups } from '../_EditorProps.js';
import razyui from '../../index.js';

/**
 * Recursively search for a block by ID, including inside group blocks.
 * @param {string} blockId
 * @param {Array} rows
 * @returns {{ block: Object, column: Object, row: Object } | null}
 */
function findBlockDeep(blockId, rows) {
    for (const row of rows) {
        for (const col of row.columns) {
            for (const block of col.blocks) {
                if (block.id === blockId) return { block, column: col, row };
                if (block.type === 'group' && block.columns) {
                    for (const gcol of block.columns) {
                        const nested = gcol.blocks.find(b => b.id === blockId);
                        if (nested) return { block: nested, column: gcol, row };
                    }
                }
            }
        }
    }
    return null;
}

// ═══════════════════════════════════════════════
// Toolbar events
// ═══════════════════════════════════════════════

/**
 * Bind click and drag events on the toolbar.
 * @param {Object} ctx — editor context
 */
export function bindToolbar(ctx) {
    ctx.toolbar.on('click', (e) => {
        const btn = e.target.closest('[data-action]');
        if (!btn) {
            // Preset in dropdown
            const presetBtn = e.target.closest('[data-preset]');
            if (presetBtn) {
                const p = PRESETS[parseInt(presetBtn.dataset.preset)];
                if (p) ctx.addRow(p.spans, getInsertRowIndex(ctx));
            }
            return;
        }
        const action = btn.dataset.action;
        switch (action) {
            case 'add-row':       ctx.addRow(undefined, getInsertRowIndex(ctx)); break;
            case 'add-col':       ctx.addColumn(); break;
            case 'add-text':      ctx.addBlock('text'); break;
            case 'add-heading':   ctx.addBlock('heading'); break;
            case 'add-image':     ctx.addBlock('image'); break;
            case 'add-button':    ctx.addBlock('button'); break;
            case 'add-divider':   ctx.addBlock('divider'); break;
            case 'add-spacer':    ctx.addBlock('spacer'); break;
            case 'add-component': ctx.showComponentPicker(); break;
            case 'undo':          ctx.undo(); break;
            case 'redo':          ctx.redo(); break;
            case 'preview':       ctx.togglePreview(); break;
            case 'export':        ctx.exportJSON(); break;
        }
    });

    // Dropdown toggle
    const dropdown = ctx.toolbar.find('.ge-tb-dropdown');
    if (dropdown.length) {
        const toggle = dropdown.find('[data-action="add-row-preset"]');
        toggle.on('click', (e) => {
            e.stopPropagation();
            dropdown.toggleClass('ge-tb-dropdown-open');
        });
        razyui(document).on('click', () => dropdown.removeClass('ge-tb-dropdown-open'), ctx.signal ? { signal: ctx.signal } : undefined);
    }

    // ── Make content-type toolbar buttons draggable ──
    const draggableActions = ['add-text', 'add-heading', 'add-image', 'add-button', 'add-divider', 'add-spacer', 'add-component'];
    const actionTypeMap = {
        'add-text': 'text', 'add-heading': 'heading', 'add-image': 'image',
        'add-button': 'button', 'add-divider': 'divider', 'add-spacer': 'spacer',
        'add-component': 'component'
    };
    ctx.toolbar.find('[data-action]').forEach(btn => {
        const action = btn.dataset.action;
        if (!draggableActions.includes(action)) return;
        btn.draggable = true;
        const $btn = razyui(btn);
        $btn.on('dragstart', (e) => {
            e.dataTransfer.setData('text/ge-new', actionTypeMap[action]);
            e.dataTransfer.effectAllowed = 'copy';
            $btn.addClass('ge-tb-btn-dragging');
        });
        $btn.on('dragend', () => {
            $btn.removeClass('ge-tb-btn-dragging');
        });
    });
}

// ═══════════════════════════════════════════════
// Body events
// ═══════════════════════════════════════════════

/**
 * Bind click events on the rows container (deselect on empty click).
 * @param {Object} ctx
 */
export function bindBodyEvents(ctx) {
    ctx.rowsContainer.on('click', (e) => {
        if (e.target === ctx.rowsContainer[0]) ctx.clearSelection();
    });
}

// ═══════════════════════════════════════════════
// Delegated events (blocks, columns, props, preview)
// ═══════════════════════════════════════════════

/**
 * Bind delegated event listeners for blocks, columns, group columns,
 * the properties panel, and the preview exit button.
 * Called once from `buildDOM` — replaces per-element inline listeners.
 * @param {Object} ctx — editor context
 */
export function bindDelegatedEvents(ctx) {
    const rc = ctx.rowsContainer;

    // ── Block mousedown — enable draggable unless over contenteditable ──
    rc.on('mousedown', (e) => {
        if (ctx.isPreview) return;
        const blockEl = e.target.closest('[data-ge-block]');
        if (blockEl && !e.target.closest('[contenteditable]')) {
            blockEl.draggable = true;
        }
    });

    // ── Block mouseup — reset draggable flag ──
    rc.on('mouseup', (e) => {
        if (ctx.isPreview) return;
        const blockEl = e.target.closest('[data-ge-block]');
        if (blockEl) blockEl.draggable = false;
    });

    // ── Block dragstart — begin block drag ──
    rc.on('dragstart', (e) => {
        if (ctx.isPreview) return;
        // Ignore row-drag handles — those are handled in bindRowHeader
        if (e.target.closest('.ge-row-drag')) return;
        const blockEl = e.target.closest('[data-ge-block]');
        if (!blockEl) return;
        e.dataTransfer.setData('text/ge-block', blockEl.dataset.geBlock);
        e.dataTransfer.effectAllowed = 'move';
        const $blockEl = razyui(blockEl);
        $blockEl.addClass('ge-block-dragging');
        setTimeout(() => $blockEl.addClass('ge-block-ghost'), 0);
    });

    // ── Block dragend — clean up drag classes ──
    rc.on('dragend', (e) => {
        if (ctx.isPreview) return;
        const blockEl = e.target.closest('[data-ge-block]');
        if (!blockEl) return;
        blockEl.draggable = false;
        razyui(blockEl).removeClass('ge-block-dragging').removeClass('ge-block-ghost');
    });

    // ── Column / group-column dragover ──
    rc.on('dragover', (e) => {
        if (ctx.isPreview) return;
        const colEl = e.target.closest('.ge-column, .ge-group-column');
        if (!colEl) return;
        if (e.dataTransfer.types.includes('text/ge-block') || e.dataTransfer.types.includes('text/ge-new')) {
            e.preventDefault();
            razyui(colEl).addClass('ge-column-dragover');
        }
    });

    // ── Column / group-column dragleave ──
    rc.on('dragleave', (e) => {
        if (ctx.isPreview) return;
        const colEl = e.target.closest('.ge-column, .ge-group-column');
        if (colEl) razyui(colEl).removeClass('ge-column-dragover');
    });

    // ── Column / group-column drop ──
    rc.on('drop', (e) => {
        if (ctx.isPreview) return;
        const colEl = e.target.closest('.ge-column, .ge-group-column');
        if (!colEl) return;
        e.preventDefault();
        const $colEl = razyui(colEl);
        $colEl.removeClass('ge-column-dragover');

        const isGroup = $colEl.hasClass('ge-group-column');

        if (isGroup) {
            // ── Group column drop ──
            const groupBlockId = colEl.dataset.geGroup;
            const gcolIdx = parseInt(colEl.dataset.geGcol);
            const result = findBlockDeep(groupBlockId, ctx.rows);
            if (!result) return;
            const col = result.block.columns[gcolIdx];

            const blockId = e.dataTransfer.getData('text/ge-block');
            if (blockId) {
                const src = findBlockDeep(blockId, ctx.rows);
                if (src) {
                    pushUndo(ctx);
                    src.column.blocks = src.column.blocks.filter(b => b.id !== blockId);
                    col.blocks.push(src.block);
                    ctx.fullRender();
                    ctx.onChange();
                }
            }
            const newType = e.dataTransfer.getData('text/ge-new');
            if (newType) {
                pushUndo(ctx);
                const block = createBlock(ctx, newType);
                col.blocks.push(block);
                ctx.fullRender();
                ctx.selectBlock(block.id);
                ctx.onChange();
            }
            e.stopPropagation();
        } else {
            // ── Regular column drop ──
            const rowId = colEl.dataset.geRow;
            const colIdx = parseInt(colEl.dataset.geCol);

            const blockId = e.dataTransfer.getData('text/ge-block');
            if (blockId) {
                const dropIdx = calcDropIndex(colEl, e.clientY);
                ctx.moveBlock(blockId, rowId, colIdx, dropIdx);
            }
            const newType = e.dataTransfer.getData('text/ge-new');
            if (newType) {
                const row = ctx.rows.find(r => r.id === rowId);
                if (!row) return;
                const col = row.columns[colIdx];
                pushUndo(ctx);
                const block = createBlock(ctx, newType);
                const dropIdx = calcDropIndex(colEl, e.clientY);
                col.blocks.splice(dropIdx, 0, block);
                ctx.fullRender();
                ctx.selectBlock(block.id);
                ctx.onChange();
            }
        }
    });

    // ── Rows-container click delegation ──
    rc.on('click', (e) => {
        if (ctx.isPreview) return;

        // Block toolbar actions (duplicate / remove)
        const actionBtn = e.target.closest('[data-block-action]');
        if (actionBtn) {
            const blockEl = actionBtn.closest('[data-ge-block]');
            if (blockEl) {
                const action = actionBtn.dataset.blockAction;
                if (action === 'remove') ctx.removeBlock(blockEl.dataset.geBlock);
                else if (action === 'duplicate') ctx.duplicateBlock(blockEl.dataset.geBlock);
            }
            e.stopPropagation();
            return;
        }

        // Image placeholder click — open URL dialog
        const imgPlaceholder = e.target.closest('.ge-img-placeholder');
        if (imgPlaceholder) {
            const blockEl = imgPlaceholder.closest('[data-ge-block]');
            if (blockEl) {
                e.stopPropagation();
                const blockId = blockEl.dataset.geBlock;
                (async () => {
                    const res = findBlockDeep(blockId, ctx.rows);
                    if (!res) return;
                    const blk = res.block;
                    const Dialog = await ctx.razyui.load('Dialog');
                    const url = await Dialog.prompt('Image URL', 'Enter image URL:', { defaultValue: blk.content || '' });
                    if (url !== null) {
                        pushUndo(ctx);
                        blk.content = url;
                        ctx.fullRender();
                        ctx.onChange();
                    }
                })();
            }
            return;
        }

        // Group column click — select the parent group block
        const groupCol = e.target.closest('.ge-group-column');
        if (groupCol && !e.target.closest('.ge-block')) {
            const groupBlockId = groupCol.dataset.geGroup;
            if (groupBlockId) {
                e.stopPropagation();
                ctx.selectBlock(groupBlockId);
            }
            return;
        }

        // Block click — select block
        const blockEl = e.target.closest('[data-ge-block]');
        if (blockEl) {
            if (e.target.closest('.ge-block-toolbar')) return;
            if (e.target.closest('[contenteditable]')) {
                ctx.selectBlock(blockEl.dataset.geBlock);
                return;
            }
            e.stopPropagation();
            ctx.selectBlock(blockEl.dataset.geBlock);
        }
    });

    // ── Content input — text / heading blocks ──
    rc.on('input', (e) => {
        if (ctx.isPreview) return;
        const content = e.target.closest('.ge-block-text, .ge-block-heading');
        if (!content) return;
        const blockEl = content.closest('[data-ge-block]');
        if (!blockEl) return;
        const result = findBlockDeep(blockEl.dataset.geBlock, ctx.rows);
        if (result) {
            result.block.content = content.textContent;
            ctx.onChange();
        }
    });

    // ── Content focusin — text / heading selects block ──
    rc.on('focusin', (e) => {
        if (ctx.isPreview) return;
        const content = e.target.closest('.ge-block-text, .ge-block-heading');
        if (!content) return;
        const blockEl = content.closest('[data-ge-block]');
        if (blockEl) ctx.selectBlock(blockEl.dataset.geBlock);
    });

    // ── Properties panel delegation ──
    const pp = ctx.propPanel;

    // Preset chip click
    pp.on('click', (e) => {
        const presetBtn = e.target.closest('[data-preset]');
        if (!presetBtn) return;
        if (!ctx.selectedRowId) return;
        const p = PRESETS[parseInt(presetBtn.dataset.preset)];
        if (p) ctx.setRowPreset(ctx.selectedRowId, p.spans);
    });

    // Row-prop change (custom spans / gap)
    pp.on('change', (e) => {
        const input = e.target.closest('[data-row-prop]');
        if (!input) return;
        const prop = input.dataset.rowProp;
        if (!ctx.selectedRowId) return;
        const row = ctx.rows.find(r => r.id === ctx.selectedRowId);
        if (!row) return;
        if (prop === 'spans') {
            const spans = input.value.trim().split(/[\s\/,]+/).map(Number).filter(n => n > 0 && n <= ctx.maxColumns);
            if (spans.length > 0) ctx.setRowPreset(row.id, spans);
        } else if (prop === 'gap') {
            pushUndo(ctx);
            row.gap = Math.max(0, parseInt(input.value) || 0);
            ctx.fullRender();
            ctx.onChange();
        }
    });

    // ── Preview exit button ──
    razyui(ctx.container).on('click', (e) => {
        if (e.target.closest('.ge-exit-preview')) {
            ctx.togglePreview();
        }
    });
}

// ═══════════════════════════════════════════════
// Row header events
// ═══════════════════════════════════════════════

/**
 * Bind events on a row header (selection, presets, actions, drag reorder).
 * @param {Object} ctx
 * @param {HTMLElement} header
 * @param {Object} row
 * @param {number} rowIdx
 */
export function bindRowHeader(ctx, header, row, rowIdx) {
    // Click row header to select row
    header.on('click', (e) => {
        if (e.target.closest('[data-preset]') || e.target.closest('[data-row-action]')) return;
        ctx.selectRow(row.id);
    });

    // Preset buttons
    header.find('[data-preset]').forEach(btn => {
        razyui(btn).on('click', (e) => {
            e.stopPropagation();
            const p = PRESETS[parseInt(btn.dataset.preset)];
            if (p) ctx.setRowPreset(row.id, p.spans);
        });
    });

    // Row actions
    header.find('[data-row-action]').forEach(btn => {
        razyui(btn).on('click', (e) => {
            e.stopPropagation();
            const action = btn.dataset.rowAction;
            if (action === 'remove') ctx.removeRow(row.id);
            else if (action === 'duplicate') ctx.duplicateRow(row.id);
            else if (action === 'add-above') ctx.addRow([12], rowIdx);
            else if (action === 'add-below') ctx.addRow([12], rowIdx + 1);
        });
    });

    // Drag reorder
    const dragHandle = header.find('.ge-row-drag');
    dragHandle.on('dragstart', (e) => {
        e.dataTransfer.setData('text/ge-row', row.id);
        e.dataTransfer.effectAllowed = 'move';
        const rowEl = header.closest('.ge-row');
        razyui(rowEl).addClass('ge-row-dragging');
    });
    dragHandle.on('dragend', () => {
        const rowEl = header.closest('.ge-row');
        if (rowEl) razyui(rowEl).removeClass('ge-row-dragging');
    });

    // Row drop target
    const rowEl = header.closest('.ge-row')[0] || header.parent()[0];
    const $rowEl = razyui(rowEl);
    $rowEl.on('dragover', (e) => {
        if (e.dataTransfer.types.includes('text/ge-row')) {
            e.preventDefault();
            $rowEl.addClass('ge-row-dragover');
        }
    });
    $rowEl.on('dragleave', () => $rowEl.removeClass('ge-row-dragover'));
    $rowEl.on('drop', (e) => {
        if (!e.dataTransfer.types.includes('text/ge-row')) return;
        e.preventDefault();
        $rowEl.removeClass('ge-row-dragover');
        const fromId = e.dataTransfer.getData('text/ge-row');
        const fromIdx = ctx.rows.findIndex(r => r.id === fromId);
        const toIdx = ctx.rows.findIndex(r => r.id === row.id);
        ctx.moveRow(fromIdx, toIdx);
    });
}

// ═══════════════════════════════════════════════
// Keyboard shortcuts
// ═══════════════════════════════════════════════

/**
 * Bind global keyboard shortcuts.
 * @param {Object} ctx
 */
export function bindKeyboard(ctx) {
    const opts = ctx.signal ? { signal: ctx.signal } : undefined;
    razyui(document).on('keydown', (e) => {
        if (!ctx.container.contains(document.activeElement) && document.activeElement !== document.body) return;
        if (e.target.closest('[contenteditable="true"]') || e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' || e.target.tagName === 'TEXTAREA') return;

        const ctrl = e.ctrlKey || e.metaKey;

        if ((e.key === 'Delete' || e.key === 'Backspace') && ctx.selectedBlockId) {
            ctx.removeBlock(ctx.selectedBlockId);
            e.preventDefault();
        } else if ((e.key === 'Delete' || e.key === 'Backspace') && ctx.selectedRowId) {
            ctx.removeRow(ctx.selectedRowId);
            e.preventDefault();
        } else if (ctrl && e.key === 'z') {
            ctx.undo(); e.preventDefault();
        } else if (ctrl && (e.key === 'y' || (e.shiftKey && e.key === 'z'))) {
            ctx.redo(); e.preventDefault();
        } else if (ctrl && e.key === 'd') {
            if (ctx.selectedBlockId) ctx.duplicateBlock(ctx.selectedBlockId);
            else if (ctx.selectedRowId) ctx.duplicateRow(ctx.selectedRowId);
            e.preventDefault();
        } else if (e.key === 'Escape') {
            if (ctx.isPreview) ctx.togglePreview();
            else ctx.clearSelection();
        }
    }, opts);
}

// ═══════════════════════════════════════════════
// Block property events
// ═══════════════════════════════════════════════

/**
 * Bind change events on block property inputs.
 * @param {Object} ctx
 * @param {HTMLElement} body
 * @param {Object} block
 */
export function bindBlockPropEvents(ctx, body, block) {
    // Name & other block props
    body.find('[data-block-prop]').forEach(input => {
        const handler = () => {
            const prop = input.dataset.blockProp;
            if (prop === 'group-spans' && block.type === 'group') {
                const spans = input.value.trim().split(/[\s\/,]+/).map(Number).filter(n => n > 0);
                if (spans.length > 0) {
                    ctx.pushUndo();
                    const allBlocks = [];
                    block.columns.forEach(c => allBlocks.push(...c.blocks));
                    block.columns = spans.map(s => ({ span: s, blocks: [] }));
                    allBlocks.forEach((b, i) => {
                        block.columns[Math.min(i, block.columns.length - 1)].blocks.push(b);
                    });
                    ctx.fullRender();
                    ctx.onChange();
                }
                return;
            }
            if (prop === 'group-gap' && block.type === 'group') {
                ctx.pushUndo();
                block.gap = Math.max(0, parseInt(input.value) || 0);
                ctx.fullRender();
                ctx.onChange();
                return;
            }
            ctx.pushUndo();
            block[prop] = input.value;
            // If componentName changed, set defaults for plugin props
            if (prop === 'componentName') {
                const comp = ctx.components.find(c => c.name === input.value);
                if (comp?.properties) {
                    if (!block.pluginProps) block.pluginProps = {};
                    comp.properties.forEach(p => {
                        if (block.pluginProps[p.name] === undefined && p.default !== undefined) {
                            block.pluginProps[p.name] = p.default;
                        }
                    });
                }
            }
            ctx.fullRender();
            ctx.selectBlock(block.id);
            ctx.onChange();
        };
        razyui(input).on('change', handler);
    });

    // Plugin-defined properties
    bindPluginProps(body, block, {
        pushUndo: () => ctx.pushUndo(),
        onChange: () => { ctx.fullRender(); ctx.selectBlock(block.id); ctx.onChange(); }
    });

    // Style props
    body.find('[data-block-style]').forEach(input => {
        razyui(input).on('change', () => {
            ctx.pushUndo();
            if (!block.style) block.style = {};
            block.style[input.dataset.blockStyle] = input.value;
            // Sync adjacent color swatch if present
            const $swatch = razyui(input).parent().find('.ge-prop-color-swatch');
            if ($swatch.length) $swatch.css('background', input.value || 'transparent');
            ctx.fullRender();
            ctx.onChange();
        });
    });
}

// ═══════════════════════════════════════════════
// ColorPicker integration
// ═══════════════════════════════════════════════

/**
 * Attach color picker popups to color swatch elements.
 * @param {Object} ctx
 * @param {HTMLElement} body
 * @param {Object} block
 */
export async function initColorPickers(ctx, body, block) {
    await attachColorPickers(body, block, {
        prefix: 'ge',
        styleAttr: 'block-style',
        container: ctx.container,
        instances: ctx._cpInstances,
        pushUndo: () => ctx.pushUndo(),
        onChange: () => { ctx.fullRender(); ctx.onChange(); }
    });
}

/**
 * Close all active color picker popups.
 * @param {Object} ctx
 */
export function closeAllColorPopups(ctx) {
    closeColorPopups(ctx._cpInstances);
}

// ═══════════════════════════════════════════════
// Component picker
// ═══════════════════════════════════════════════

/**
 * Show the component picker menu (or add directly if only one component).
 * @param {Object} ctx
 */
export function showComponentPicker(ctx) {
    if (!ctx.components.length) return;
    if (ctx.components.length === 1) {
        // Only one component, add it directly
        const comp = ctx.components[0];
        const block = ctx.addBlock('component', { componentName: comp.name });
        // Set default plugin props
        if (comp.properties) {
            if (!block.pluginProps) block.pluginProps = {};
            comp.properties.forEach(p => {
                if (p.default !== undefined) block.pluginProps[p.name] = p.default;
            });
        }
        ctx.fullRender();
        ctx.selectBlock(block.id);
        return;
    }
    // Show a dropdown menu near the component button
    const existing = razyui(ctx.container).find('.ge-comp-picker');
    if (existing.length) { existing[0].remove(); return; }

    const compBtn = ctx.toolbar.find('[data-action="add-component"]');
    const btnRect = compBtn.getRect();
    const rootRect = ctx.container.getBoundingClientRect();

    const menu = el('div', 'ge-comp-picker');
    PART.COMP_PICKER.apply(menu);
    menu.css('position', 'absolute')
        .css('left', (btnRect.left - rootRect.left) + 'px')
        .css('top', (btnRect.bottom - rootRect.top + 4) + 'px')
        .css('z-index', '9999');

    ctx.components.forEach(comp => {
        const item = el('button', 'ge-comp-picker-item');
        PART.CP_ITEM.apply(item);
        item.text(`${comp.icon || '\u29C9'} ${comp.name}`)
            .on('click', () => {
            const block = ctx.addBlock('component', { componentName: comp.name });
            if (comp.properties) {
                if (!block.pluginProps) block.pluginProps = {};
                comp.properties.forEach(p => {
                    if (p.default !== undefined) block.pluginProps[p.name] = p.default;
                });
            }
            ctx.fullRender();
            ctx.selectBlock(block.id);
            menu[0].remove();
        });
        menu.append(item);
    });

    razyui(ctx.container).append(menu);

    // Close on click outside (use signal for cleanup on destroy)
    const closeAC = new AbortController();
    const close = (e) => {
        if (!menu.contains(e.target) && e.target !== compBtn[0]) {
            menu[0].remove();
            closeAC.abort();
        }
    };
    // Also abort on component destroy
    if (ctx.signal) ctx.signal.addEventListener('abort', () => closeAC.abort());
    setTimeout(() => document.addEventListener('mousedown', close, { capture: true, signal: closeAC.signal }), 0);
}
