/**
 * @fileoverview GridEditor state — data model creation and mutation
 *               operations (rows, blocks, undo/redo).
 *
 * Every function receives the `ctx` context bridge so it can read and
 * write the editor's private state without direct field access.
 *
 * @module module/GridEditor/state
 */

import { getBlockDefaults } from './constants.js';
import { findBlock, findTargetColumn } from './helpers.js';

// ═══════════════════════════════════════════════
// ID generation
// ═══════════════════════════════════════════════

/**
 * Generate a unique ID string.
 * @param {Object} ctx
 * @returns {string}
 */
export function genId(ctx) {
    return 'ge-' + (ctx.nextId++);
}

// ═══════════════════════════════════════════════
// Data object factories
// ═══════════════════════════════════════════════

/**
 * Create a new row data object.
 * @param {Object} ctx
 * @param {number[]} [spans]
 * @returns {Object}
 */
export function createRow(ctx, spans) {
    spans = spans || [12];
    return {
        id: genId(ctx),
        gap: ctx.defaultGap,
        columns: spans.map(span => ({ span, blocks: [] })),
    };
}

/**
 * Create a new block data object with type defaults.
 * @param {Object} ctx
 * @param {string} type
 * @param {Object} [props]
 * @returns {Object}
 */
export function createBlock(ctx, type, props = {}) {
    const defaults = getBlockDefaults(ctx.defaultGap);
    const d = defaults[type] || defaults.text;
    return {
        id: genId(ctx),
        type,
        name: props.name || (type.charAt(0).toUpperCase() + type.slice(1)),
        content: props.content ?? d.content,
        style: { ...d.style, ...(props.style || {}) },
        ...(d.columns ? { columns: d.columns, gap: d.gap } : {}),
        ...(d.componentName !== undefined ? { componentName: props.componentName || d.componentName } : {}),
        ...(d.pluginProps ? { pluginProps: { ...(d.pluginProps || {}), ...(props.pluginProps || {}) } } : {}),
    };
}

// ═══════════════════════════════════════════════
// Undo / Redo
// ═══════════════════════════════════════════════

/**
 * Push the current rows state onto the undo stack.
 * @param {Object} ctx
 */
export function pushUndo(ctx) {
    ctx.undoStack.push(JSON.parse(JSON.stringify(ctx.rows)));
    if (ctx.undoStack.length > 80) ctx.undoStack.shift();
    ctx.redoStack = [];
}

/**
 * Undo the last operation.
 * @param {Object} ctx
 */
export function undoOp(ctx) {
    if (!ctx.undoStack.length) return;
    ctx.redoStack.push(JSON.parse(JSON.stringify(ctx.rows)));
    ctx.rows = ctx.undoStack.pop();
    ctx.selectedBlockId = null;
    ctx.selectedRowId = null;
    ctx.fullRender();
}

/**
 * Redo the last undone operation.
 * @param {Object} ctx
 */
export function redoOp(ctx) {
    if (!ctx.redoStack.length) return;
    ctx.undoStack.push(JSON.parse(JSON.stringify(ctx.rows)));
    ctx.rows = ctx.redoStack.pop();
    ctx.selectedBlockId = null;
    ctx.selectedRowId = null;
    ctx.fullRender();
}

// ═══════════════════════════════════════════════
// Row operations
// ═══════════════════════════════════════════════

/**
 * Add a new row.
 * @param {Object} ctx
 * @param {number[]} [spans]
 * @param {number}   [index]
 * @returns {Object} the created row
 */
export function addRow(ctx, spans, index) {
    pushUndo(ctx);
    const row = createRow(ctx, spans);
    if (index !== undefined) {
        ctx.rows.splice(index, 0, row);
    } else {
        ctx.rows.push(row);
    }
    ctx.fullRender();
    ctx.selectRow(row.id);
    ctx.onChange();
    return row;
}

/**
 * Remove a row by ID.
 * @param {Object} ctx
 * @param {string} rowId
 */
export function removeRow(ctx, rowId) {
    pushUndo(ctx);
    ctx.rows = ctx.rows.filter(r => r.id !== rowId);
    if (ctx.selectedRowId === rowId) ctx.selectedRowId = null;
    ctx.fullRender();
    ctx.refreshProps();
    ctx.onChange();
}

/**
 * Move a row from one index to another.
 * @param {Object} ctx
 * @param {number} fromIdx
 * @param {number} toIdx
 */
export function moveRow(ctx, fromIdx, toIdx) {
    if (fromIdx === toIdx || fromIdx < 0 || toIdx < 0) return;
    pushUndo(ctx);
    const [moved] = ctx.rows.splice(fromIdx, 1);
    ctx.rows.splice(toIdx, 0, moved);
    ctx.fullRender();
    ctx.onChange();
}

/**
 * Set a row's column layout to the given preset spans.
 * @param {Object} ctx
 * @param {string} rowId
 * @param {number[]} spans
 */
export function setRowPreset(ctx, rowId, spans) {
    const row = ctx.rows.find(r => r.id === rowId);
    if (!row) return;
    pushUndo(ctx);

    // Gather all existing blocks from current columns
    const allBlocks = [];
    row.columns.forEach(col => allBlocks.push(...col.blocks));

    // Create new columns from spans
    row.columns = spans.map(span => ({ span, blocks: [] }));

    // Redistribute blocks: fill columns left-to-right
    allBlocks.forEach((block, i) => {
        const colIdx = Math.min(i, row.columns.length - 1);
        row.columns[colIdx].blocks.push(block);
    });

    ctx.fullRender();
    ctx.refreshProps();
    ctx.onChange();
}

/**
 * Add a column to the selected (or last) row.
 * @param {Object} ctx
 */
export function addColumn(ctx) {
    // Find the target row from selection
    let row = null;
    if (ctx.selectedRowId) {
        row = ctx.rows.find(r => r.id === ctx.selectedRowId);
    } else if (ctx.selectedBlockId) {
        const result = findBlock(ctx.selectedBlockId, ctx.rows);
        if (result) row = result.row;
    }
    if (!row) {
        // Fallback: last row, or create a new one
        if (ctx.rows.length) {
            row = ctx.rows[ctx.rows.length - 1];
        } else {
            addRow(ctx);
            return;
        }
    }
    const newCount = row.columns.length + 1;
    const base = Math.floor(ctx.maxColumns / newCount);
    const remainder = ctx.maxColumns - base * newCount;
    const spans = Array.from({ length: newCount }, (_, i) => base + (i < remainder ? 1 : 0));
    setRowPreset(ctx, row.id, spans);
}

/**
 * Duplicate a row.
 * @param {Object} ctx
 * @param {string} rowId
 */
export function duplicateRow(ctx, rowId) {
    const row = ctx.rows.find(r => r.id === rowId);
    if (!row) return;
    pushUndo(ctx);
    const dup = JSON.parse(JSON.stringify(row));
    dup.id = genId(ctx);
    // Re-ID all blocks
    dup.columns.forEach(col => {
        col.blocks.forEach(b => { b.id = genId(ctx); });
    });
    const idx = ctx.rows.indexOf(row);
    ctx.rows.splice(idx + 1, 0, dup);
    ctx.fullRender();
    ctx.selectRow(dup.id);
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Block operations
// ═══════════════════════════════════════════════

/**
 * Add a new block to the current target column.
 * @param {Object} ctx
 * @param {string} type
 * @param {Object} [props]
 * @returns {Object} the created block
 */
export function addBlockOp(ctx, type, props = {}) {
    // Add block to: selected column if a block is selected, or first column of last row
    const target = findTargetColumn(ctx);
    if (!target) {
        // No rows — add one first
        const row = addRow(ctx, [12]);
        pushUndo(ctx);
        const block = createBlock(ctx, type, props);
        row.columns[0].blocks.push(block);
        ctx.fullRender();
        ctx.selectBlock(block.id);
        ctx.onChange();
        return block;
    }
    pushUndo(ctx);
    const block = createBlock(ctx, type, props);
    target.blocks.push(block);
    ctx.fullRender();
    ctx.selectBlock(block.id);
    ctx.onChange();
    return block;
}

/**
 * Remove a block by ID.
 * @param {Object} ctx
 * @param {string} blockId
 */
export function removeBlock(ctx, blockId) {
    pushUndo(ctx);
    ctx.rows.forEach(row => {
        row.columns.forEach(col => {
            col.blocks = col.blocks.filter(b => b.id !== blockId);
        });
    });
    if (ctx.selectedBlockId === blockId) ctx.selectedBlockId = null;
    ctx.fullRender();
    ctx.refreshProps();
    ctx.onChange();
}

/**
 * Duplicate a block.
 * @param {Object} ctx
 * @param {string} blockId
 */
export function duplicateBlock(ctx, blockId) {
    const { block, column } = findBlock(blockId, ctx.rows) || {};
    if (!block || !column) return;
    pushUndo(ctx);
    const dup = JSON.parse(JSON.stringify(block));
    dup.id = genId(ctx);
    dup.name += ' copy';
    const idx = column.blocks.indexOf(block);
    column.blocks.splice(idx + 1, 0, dup);
    ctx.fullRender();
    ctx.selectBlock(dup.id);
    ctx.onChange();
}

/**
 * Move a block to a different column / position.
 * @param {Object} ctx
 * @param {string} blockId
 * @param {string} targetRowId
 * @param {number} targetColIdx
 * @param {number} [targetBlockIdx]
 */
export function moveBlockOp(ctx, blockId, targetRowId, targetColIdx, targetBlockIdx) {
    const { block, column: srcCol } = findBlock(blockId, ctx.rows) || {};
    if (!block || !srcCol) return;
    const targetRow = ctx.rows.find(r => r.id === targetRowId);
    if (!targetRow) return;
    const targetCol = targetRow.columns[targetColIdx];
    if (!targetCol) return;

    pushUndo(ctx);
    srcCol.blocks = srcCol.blocks.filter(b => b.id !== blockId);
    if (targetBlockIdx !== undefined) {
        targetCol.blocks.splice(targetBlockIdx, 0, block);
    } else {
        targetCol.blocks.push(block);
    }
    ctx.fullRender();
    ctx.onChange();
}

/**
 * Load layout data (JSON).
 * @param {Object} ctx
 * @param {Object} data — { rows: [...] }
 */
export function loadData(ctx, data) {
    if (!data?.rows) return;
    ctx.rows = data.rows;
    ctx.nextId = 1;
    // Walk all rows/blocks to find max ID
    const walk = (items) => {
        items.forEach(item => {
            if (item.id) {
                const n = parseInt(item.id.replace('ge-', ''), 10);
                if (!isNaN(n) && n >= ctx.nextId) ctx.nextId = n + 1;
            }
            if (item.columns) item.columns.forEach(col => {
                if (col.blocks) walk(col.blocks);
            });
        });
    };
    walk(ctx.rows);
    ctx.selectedBlockId = null;
    ctx.selectedRowId = null;
    ctx.fullRender();
}
