/**
 * @fileoverview GridEditor helpers — pure utility functions for DOM creation,
 *               HTML escaping, block lookup, and layout calculations.
 *
 * @module module/GridEditor/helpers
 */

import razyui from '../../index.js';

// ═══════════════════════════════════════════════
// DOM utilities
// ═══════════════════════════════════════════════

/**
 * Create a DOM element with an optional CSS class string.
 * @param {string} tag — HTML tag name
 * @param {string} [cls] — space-separated class names
 * @returns {Elements}
 */
export function el(tag, cls) {
    return razyui.el(tag, cls ? { className: cls } : undefined);
}

/**
 * Escape a string for safe HTML attribute / text insertion.
 * @param {string} str
 * @returns {string}
 */
export function esc(str) {
    return String(str || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;');
}

// ═══════════════════════════════════════════════
// Layout calculations
// ═══════════════════════════════════════════════

/**
 * Determine the insertion index for a dropped block inside a column element.
 * @param {HTMLElement} colEl — the column DOM element
 * @param {number} clientY — mouse Y coordinate
 * @returns {number}
 */
export function calcDropIndex(colEl, clientY) {
    const blocks = razyui(colEl).find('.ge-block');
    for (let i = 0; i < blocks.length; i++) {
        const rect = blocks[i].getBoundingClientRect();
        if (clientY < rect.top + rect.height / 2) return i;
    }
    return blocks.length;
}

/**
 * Check whether a row's column spans match the given preset spans.
 * @param {Object} row
 * @param {number[]} spans
 * @returns {boolean}
 */
export function matchPreset(row, spans) {
    if (row.columns.length !== spans.length) return false;
    return row.columns.every((c, i) => c.span === spans[i]);
}

// ═══════════════════════════════════════════════
// Data lookups
// ═══════════════════════════════════════════════

/**
 * Find a block by ID within the row/column tree.
 * @param {string} blockId
 * @param {Array} rows
 * @returns {{ block: Object, column: Object, row: Object } | null}
 */
export function findBlock(blockId, rows) {
    for (const row of rows) {
        for (const col of row.columns) {
            const block = col.blocks.find(b => b.id === blockId);
            if (block) return { block, column: col, row };
        }
    }
    return null;
}

/**
 * Find the target column for inserting a new block.
 * Uses the current selection or falls back to the last row's first column.
 * @param {Object} ctx — editor context
 * @returns {Object|null} — column data object
 */
export function findTargetColumn(ctx) {
    // If a block is selected, return its column
    if (ctx.selectedBlockId) {
        const result = findBlock(ctx.selectedBlockId, ctx.rows);
        if (result) return result.column;
    }
    // If a row is selected, return its first column
    if (ctx.selectedRowId) {
        const row = ctx.rows.find(r => r.id === ctx.selectedRowId);
        if (row && row.columns.length) return row.columns[0];
    }
    // Default: last row, first column
    if (ctx.rows.length) {
        const lastRow = ctx.rows[ctx.rows.length - 1];
        if (lastRow.columns.length) return lastRow.columns[0];
    }
    return null;
}

/**
 * Determine the row index at which to insert a new row (after the selection).
 * @param {Object} ctx — editor context
 * @returns {number|undefined} — index, or undefined to append
 */
export function getInsertRowIndex(ctx) {
    let rowId = ctx.selectedRowId;
    if (!rowId && ctx.selectedBlockId) {
        const result = findBlock(ctx.selectedBlockId, ctx.rows);
        if (result) rowId = result.row.id;
    }
    if (rowId) {
        const idx = ctx.rows.findIndex(r => r.id === rowId);
        if (idx >= 0) return idx + 1;
    }
    return undefined;
}
